class Node:
 def __init__(self, value):
 self.value = value
 self.next = None

class CircularSinglyLinkedList:
 def __init__(self):
 self.head = None
 self.tail = None

 def insert_at_beginning(self, value):
 new_node = Node(value)
 if self.head is None:
 self.head = new_node
 self.tail = new_node
 new_node.next = new_node
 else:
 new_node.next = self.head
 self.tail.next = new_node
 self.head = new_node

 def insert_at_end(self, value):
 new_node = Node(value)
 if self.head is None:
 self.head = new_node
 self.tail = new_node
 new_node.next = new_node
 else:
 new_node.next = self.head
 self.tail.next = new_node
 self.tail = new_node

 def delete_from_beginning(self):
 if self.head is None:
 return
 if self.head.next is self.head:
 self.head = None
 self.tail = None
 else:
 self.head = self.head.next
 self.tail.next = self.head

 def delete_from_end(self):
 if self.head is None:
 return
 if self.head.next is self.head:
 self.head = None
 self.tail = None
 else:
 current = self.head
 while current.next is not self.head:
 current = current.next
 current.next = self.head
 self.tail = current

typedef struct Node {
 int value;
 struct Node* next;
} Node;

typedef struct CircularSinglyLinkedList {
 Node* head;
 Node* tail;
} CircularSinglyLinkedList;

void insert_at_beginning(CircularSinglyLinkedList* list, int value) {
 Node* new_node = (Node*)malloc(sizeof(Node));
 new_node->value = value;
 if (list->head == NULL) {
 list->head = new_node;
 list->tail = new_node;
 new_node->next = new_node;
 } else {
 new_node->next = list->head;
 list->tail->next = new_node;
 list->head = new_node;
 }
}

void insert_at_end(CircularSinglyLinkedList* list, int value) {
 Node* new_node = (Node*)malloc(sizeof(Node));
 new_node->value = value;
 if (list->head == NULL) {
 list->head = new_node;
 list->tail = new_node;
 new_node->next = new_node;
 } else {
 new_node->next = list->head;
 list->tail->next = new_node;
 list->tail = new_node;
 }
}

void delete_from_beginning(CircularSinglyLinkedList* list) {
 if (list->head == NULL) return;
 if (list->head->next == list->head) {
 free(list->head);
 list->head = NULL;
 list->tail = NULL;
 } else {
 list->head = list->head->next;
 list->tail->next = list->head;
 }
}

void delete_from_end(CircularSinglyLinkedList* list) {
 if (list->head == NULL) return;
 if (list->head->next == list->head) {
 free(list->head);
 list->head = NULL;
 list->tail = NULL;
 } else {
 Node* current = list->head;
 while (current->next != list->head) {
 current = current->next;
 }
 current->next = list->head;
 list->tail = current;
 }
}
